13→const BlogOptimizer: React.FC<Props> = ({ onBack, user, onDeductCredits, onNavigateToPublisher }) => {
14→  const [topic, setTopic] = useState('');
15→  const [url, setUrl] = useState('');
16→  const [result, setResult] = useState<string | null>(null);
17→  const [isGenerating, setIsGenerating] = useState(false);
18→  const [isWritingArticle, setIsWritingArticle] = useState(false);
19→  const [copied, setCopied] = useState(false);
20→  const [mode, setMode] = useState<'brief' | 'article'>('brief');
21→
22→  const BRIEF_COST = 20;
23→  const FULL_ARTICLE_COST = 50;
24→
25→  const handleGenerateBrief = async (e: React.FormEvent) => {
26→    e.preventDefault();
27→    if (!topic && !url) {
28→      alert("Veuillez saisir au moins un sujet ou une URL.");
29→      return;
30→    }
31→
32→    if (onDeductCredits(BRIEF_COST)) {
33→      setIsGenerating(true);
34→      setMode('brief');
35→      try {
36→        const output = await generateBlogArchitecture(topic, url);
37→        setResult(output);
38→      } catch (error) {
39→        console.error(error);
40→        alert("Erreur lors de la génération.");
41→      } finally {
42→        setIsGenerating(false);
43→      }
44→    }
45→  };
46→
47→  const handleWriteForMe = async () => {
48→    if (!result) return;
49→
50→    if (onNavigateToPublisher) {
51→        onNavigateToPublisher({
52→            topic: topic || "Sujet non spécifié",
53→            url: url || "",
54→            brief: result
55→        });
56→    }
57→  };
58→
59→  const handleCopy = () => {
60→    if (result) {
61→      navigator.clipboard.writeText(result);
62→      setCopied(true);
63→      setTimeout(() => setCopied(false), 2000);
64→    }
65→  };
66→
67→  const handleDownload = () => {
68→    if (result) {
69→      const blob = new Blob([result], { type: 'text/markdown' });
70→      const url = URL.createObjectURL(blob);
71→      const a = document.createElement('a');
72→      a.href = url;
73→      a.download = `${mode === 'article' ? 'Article_AEO' : 'Brief'}_${topic.replace(/\s+/g, '_') || 'Optimized'}.md`;
74→      document.body.appendChild(a);
75→      a.click();
76→      document.body.removeChild(a);
77→      URL.revokeObjectURL(url);
78→    }
79→  };
